class Solution:
    def xorQueries(self, arr, queries):
        pre = [0] * (len(arr) + 1)
        for i, v in enumerate(arr):
            pre[i + 1] = pre[i] ^ v
        return [pre[r + 1] ^ pre[l] for l, r in queries]

