var xorQueries = function(arr, queries) {
    const pre = new Array(arr.length + 1).fill(0);
    for (let i = 0; i < arr.length; i++) {
        pre[i + 1] = pre[i] ^ arr[i];
    }
    return queries.map(([l, r]) => pre[r + 1] ^ pre[l]);
};
